431	        // height are in advance (before inserting it into the DOM) so that we
432	        // can ensure it doesn't grow past those limits. We don't always have
433	        // this information, especially in places where <Renderer /> is used
434	        // to render inline Markdown images within a widget. See Radio, Sorter,
435	        // Matcher, etc.
436	        const responsive = this.props.responsive && !!(width && height);
437	
438	        // An additional <Graphie /> may be inserted after the image/graphie
439	        // pair. Only used by the image widget, for its legacy labels support.
440	        // Note that since the image widget always provides width and height
441	        // data, extraGraphie can be ignored for unresponsive images.
442	        let extraGraphie;
443	        // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
444	        if (this.props.extraGraphie && this.props.extraGraphie.labels.length) {
445	            extraGraphie = (
446	                <Graphie
447	                    box={this.props.extraGraphie.box}
448	                    range={this.props.extraGraphie.range}
449	                    options={{labels: this.props.extraGraphie.labels}}
450	                    responsive={true}
451	                    addMouseLayer={false}
452	                    setup={this.setupGraphie}
453	                />
454	            );
455	        }
456	
457	        // If preloader is undefined, we use the default. If it's
458	        // null, there will be no preloader in use.
459	        const preloaderBaseFunc =
460	            this.props.preloader === undefined
461	                ? defaultPreloader
462	                : this.props.preloader;
463	
464	        // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
465	        const preloader = preloaderBaseFunc
466	            ? () => preloaderBaseFunc(dimensions)
467	            : null;
