474	                // When gif controls are active (isGifPlaying is defined), wrap
475	                // ImageLoader in a div so we can querySelector the <img> for
476	                // canvas capture. The canvas is a non-first child of
477	                // FixedToResponsive, so it gets position:absolute coverage via
478	                // the .fixed-to-responsive > :not(:first-child) CSS rule.
479	                const isGifControlled = this.props.isGifPlaying !== undefined;
480	
481	                const imageContent = (
482	                    <>
483	                        {!isGifControlled && (
484	                            <>
485	                                <ImageLoader
486	                                    src={imageSrc}
487	                                    imgProps={imageProps}
488	                                    preloader={preloader}
489	                                    onUpdate={this.handleUpdate}
490	                                />
491	                                {extraGraphie}
492	                            </>
493	                        )}
494	                        {isGifControlled && (
495	                            <GifImage
496	                                src={imageSrc}
497	                                alt={this.props.alt}
498	                                width={this.props.width}
499	                                height={this.props.height}
500	                                scale={this.props.scale}
501	                                isPlaying={!!this.props.isGifPlaying}
502	                                onLoop={this.props.onGifLoop ?? (() => {})}
