535	            // (i.e. markdown images inside tables or widgets, or
536	            // Image widgets with no size saved)
537	            imageProps.style = dimensions;
538	            return (
539	                <ImageLoader
540	                    src={imageSrc}
541	                    preloader={preloader}
542	                    imgProps={imageProps}
543	                    onUpdate={this.handleUpdate}
