600	                        onUpdate={this.handleUpdate}
601	                        preloader={preloader}
602	                        imgProps={imageProps}
603	                    />
604	                    {graphie}
605	                    {extraGraphie}
606	                </>
607	            );
608	
609	            return (
610	                <FixedToResponsive
611	                    className="svg-image"
612	                    width={width}
613	                    height={height}
614	                    constrainHeight={this.props.constrainHeight}
615	                    scale={this.props.scale}
616	                >
617	                    {imageContent}
618	                    {this.props.allowZoom && (
619	                        <ZoomImageButton
620	                            {...this.props}
621	                            imgSrc={imageUrl}
622	                            width={this.props.width}
623	                            height={this.props.height}
624	                        />
625	                    )}
626	                </FixedToResponsive>
627	            );
628	        }
629	
630	        // Unresponsive Graphie images (i.e. markdown Graphie images in tables)
631	        imageProps.style = dimensions;
632	        return (
633	            <div className="unresponsive-svg-image" style={dimensions}>
634	                <ImageLoader
635	                    src={imageUrl}
636	                    onLoad={this.onImageLoad}
637	                    onUpdate={this.handleUpdate}
638	                    preloader={preloader}
639	                    imgProps={imageProps}
