/**
 * [Most of] the Perseus client API.
 *
 * If making a change to this file, or otherwise to the perseus
 * API, you should increment:
 *  * the perseus api major version if it is a breaking change
 *  * the perseus api minor version if it is an additive-only change
 *  * nothing if it is purely a bug fix.
 *
 * Callbacks passed to Renderer/ItemRenderer:
 *  * onFocusChange: (newFocusPath, oldFocusPath, keypadDOMNode)
 *    Called when the user focus changes. The first two parameters are `path`
 *    arrays uniquely identifying the respect inputs. The third parameter,
 *    `keypadDOMNode`, is the DOM node of the custom keypad, or `null` if the
 *    keypad is disabled, which can be used by clients to accommodate for the
 *    appearance of the keypad on the screen.
 *    When focus changes to or from nothing being selected, `path` will be null.
 *  * interactionCallback: Called when the user interacts with a widget.
 *  * answerableCallback: Called with the current `answerability` of the
 *    problem, e.g. whether all required fields have input.
 *  * getAnotherHint: If provided, a button is rendered at the bottom of the
 *    hints (only when at least one hint has been shown, and not all hints
 *    have been shown) allowing the user to take another hint. This function
 *    is then called when the user clicks the button.
 *
 * Stable CSS ClassNames:
 * These are css class names that will continue to preserve their
 * semantic meaning across the same perseus api major version.
 */
import PropTypes from "prop-types";
import * as React from "react";

import type {APIOptionsWithDefaults} from "./types";

export const ApiOptions = {
    propTypes: PropTypes.shape({
        isArticle: PropTypes.bool.isRequired,

        onFocusChange: PropTypes.func.isRequired,
        showAlignmentOptions: PropTypes.bool.isRequired,
        readOnly: PropTypes.bool.isRequired,

        answerableCallback: PropTypes.func,
        getAnotherHint: PropTypes.func,
        interactionCallback: PropTypes.func,

        // If imagePlaceholder or widgetPlaceholder are set, perseus will
        // render the placeholder instead of the image or widget node.
        imagePlaceholder: PropTypes.node,
        widgetPlaceholder: PropTypes.node,

        // Base React elements that can be used in place of the standard DOM
        // DOM elements. For example, when provided, <Link /> will be used
        // in place of <a />. This allows clients to provide pre-styled
        // components or components with custom behavior.
        baseElements: PropTypes.shape({
            // The <Link /> component provided here must adhere to the same
            // interface as React's base <a /> component.
            Link: PropTypes.func,
        }),

        // Function that takes dimensions and returns a React component
        // to display while an image is loading
        imagePreloader: PropTypes.func,

        // Function that takes an object argument. The object should
        // include type and id, both strings, at least and can optionally
        // include a boolean "correct" value. This is used for keeping
        // track of widget interactions.
        trackInteraction: PropTypes.func,

        // A boolean that indicates whether or not a custom keypad is
        // being used.  For mobile web this will be the ProvidedKeypad
        // component.  In this situation we use the MathInput component
        // from the math-input repo instead of the existing perseus math
        // input components.
        customKeypad: PropTypes.bool,

        // If this is provided, it is called instead of appending an instance
        // of `math-input`'s keypad to the body. This is used by the native
        // apps so they can have the keypad be defined on the native side.
        // It is called with an function that, when called, blurs the input,
        // and is expected to return an object of the shape
        // keypadElementPropType from math-input/src/prop-types.js.
        nativeKeypadProxy: PropTypes.func,

        // Indicates whether or not to use mobile styling.
        isMobile: PropTypes.bool,

        // Indicates whether or not to use mobile app styling.
        isMobileApp: PropTypes.bool,

        // The color used for the hint progress indicator (eg. 1 / 3)
        hintProgressColor: PropTypes.string,
    }).isRequired,

    // eslint-disable-next-line no-restricted-syntax
    defaults: {
        isArticle: false,
        isMobile: false,
        isMobileApp: false,
        editingDisabled: false,
        onFocusChange: function () {},
        showAlignmentOptions: false,
        readOnly: false,
        baseElements: {
            Link: (
                props: any,
            ): React.ReactElement<React.ComponentProps<"a">> => {
                const {children, ...rest} = props;
                return <a {...rest}>{children}</a>;
            },
        },
    } as APIOptionsWithDefaults,
} as const;

export const ClassNames = {
    RENDERER: "perseus-renderer",
    TWO_COLUMN_RENDERER: "perseus-renderer-two-columns",
    RESPONSIVE_RENDERER: "perseus-renderer-responsive",
    INPUT: "perseus-input",
    FOCUSED: "perseus-focused",
    MOBILE: "perseus-mobile",
} as const;

import {isFeatureOn} from "@khanacademy/perseus-core";
import {useOnMountEffect} from "@khanacademy/wonder-blocks-core";
import * as React from "react";

import AssetContext from "../../asset-context";
import {PerseusI18nContext} from "../../components/i18n-context";
import SvgImage from "../../components/svg-image";
import {useDependencies} from "../../dependencies";
import Renderer from "../../renderer";

import {ImageInfoArea} from "./components/image-info-area";
import styles from "./image-widget.module.css";
import {isGif} from "./utils";

import type {ImageWidgetProps} from "./image.class";

export const ImageComponent = (props: ImageWidgetProps) => {
    const {
        apiOptions,
        alt,
        backgroundImage,
        box,
        caption,
        longDescription,
        decorative,
        linterContext,
        labels,
        range,
        title,
        trackInteraction,
        widgetId,
    } = props;
    const context = React.useContext(PerseusI18nContext);
    const {analytics} = useDependencies();
    const gifControlsFF = isFeatureOn(
        {apiOptions},
        "image-widget-upgrade-gif-controls",
    );

    // Gif should be paused on initial render for a11y.
    const [isGifPlaying, setIsGifPlaying] = React.useState<boolean>(false);

    useOnMountEffect(() => {
        analytics.onAnalyticsEvent({
            type: "perseus:widget:rendered:ti",
            payload: {
                widgetSubType: "null",
                widgetType: "image",
                widgetId: widgetId,
            },
        });
    });

    // If the backgroundImage.url changes (likely in the editor preview)
    // we will stop any gif from playing.
    React.useEffect(() => {
        setIsGifPlaying(false);
    }, [backgroundImage.url]);

    if (!backgroundImage.url) {
        return null;
    }

    const imageIsGif = isGif(backgroundImage.url);

    let scale = props.scale;
    // Set the scale to 1 if the scale is invalid.
    if (scale <= 0 || scale === Infinity || scale === -Infinity) {
        scale = 1;
    }

    const svgImage = (
        <AssetContext.Consumer>
            {({setAssetStatus}) => (
                <SvgImage
                    src={backgroundImage.url!}
                    apiOptions={apiOptions}
                    // Between the original image size and the saved background
                    // image size, use the larger size to determine if the
                    // image is large enough to allow zooming.
                    width={backgroundImage.width}
                    height={backgroundImage.height}
                    scale={scale}
                    preloader={apiOptions.imagePreloader}
                    extraGraphie={{
                        box: box,
                        range: range,
                        labels: labels,
                    }}
                    trackInteraction={trackInteraction}
                    zoomToFullSizeOnMobile={apiOptions.isMobile}
                    constrainHeight={apiOptions.isMobile}
                    allowFullBleed={apiOptions.isMobile}
                    // Only allow zooming if the image is not decorative and not a GIF.
                    allowZoom={!decorative && !imageIsGif}
                    alt={decorative || caption === alt ? "" : alt}
                    setAssetStatus={setAssetStatus}
                    isGifPlaying={
                        gifControlsFF && imageIsGif ? isGifPlaying : undefined
                    }
                    onGifLoop={
                        gifControlsFF && imageIsGif
                            ? () => setIsGifPlaying(false)
                            : undefined
                    }
                />
            )}
        </AssetContext.Consumer>
    );

    // Set the max width of the image container to the width saved inside
    // `backgroundImage` (if it is set at all) - this is the width intended
    // to be used when rendering the image within the content item.
    const maxWidth = backgroundImage.width
        ? backgroundImage.width * scale
        : undefined;
    // Only set the width if we're not setting maxWidth.
    // We need `width: fit-content` to handle the case where background.width
    // and background.height are undefined, so that the container sets the
    // bounds based on the natural image size, and the caption aligns
    // properly with the image.
    const width = maxWidth ? undefined : "fit-content";

    // Early return for decorative images
    if (decorative) {
        return (
            <figure
                className="perseus-image-widget"
                style={{
                    maxWidth: maxWidth,
                    width: width,
                }}
            >
                {svgImage}
            </figure>
        );
    }

    return (
        <figure
            className="perseus-image-widget"
            style={{
                maxWidth: maxWidth,
                width: width,
            }}
        >
            {/* Title */}
            {title && (
                <div className={`perseus-image-title ${styles.titleContainer}`}>
                    {/* The Renderer component is used here so that the title
                        can support Markdown and TeX. */}
                    <Renderer
                        content={title}
                        apiOptions={apiOptions}
                        linterContext={linterContext}
                        strings={context.strings}
                    />
                </div>
            )}

            {/* Image */}
            {svgImage}

            {/* Description & Caption */}
            {((gifControlsFF && imageIsGif) || caption || longDescription) && (
                <ImageInfoArea
                    isGifPlaying={isGifPlaying}
                    setIsGifPlaying={setIsGifPlaying}
                    {...props}
                />
            )}
        </figure>
    );
};

import {isFeatureOn} from "@khanacademy/perseus-core";
import {sizing} from "@khanacademy/wonder-blocks-tokens";
import {Heading} from "@khanacademy/wonder-blocks-typography";
import * as React from "react";

import AssetContext from "../../../asset-context";
import {SvgImage} from "../../../components";
import {PerseusI18nContext} from "../../../components/i18n-context";
import Renderer from "../../../renderer";
import styles from "../image-widget.module.css";
import {isGif, isSvg} from "../utils";

import {GifControlsButton} from "./gif-controls-button";

import type {CommonImageProps, GifProps} from "./image-info-area";

const MODAL_HEIGHT = 568;

type Props = CommonImageProps &
    GifProps & {
        captionId: string;
        longDescId: string;
    };

export default function ExploreImageModalContent({
    backgroundImage,
    scale: contentScale,
    caption,
    alt,
    longDescription,
    linterContext,
    apiOptions,
    box,
    labels,
    range,
    captionId,
    longDescId,
}: Props) {
    const [isGifPlaying, setIsGifPlaying] = React.useState(false);
    const context = React.useContext(PerseusI18nContext);

    if (!backgroundImage.url) {
        return null;
    }

    const gifControlsFF = isFeatureOn(
        {apiOptions},
        "image-widget-upgrade-gif-controls",
    );

    const imageIsGif = isGif(backgroundImage.url);
    const imageIsSvg = isSvg(backgroundImage.url);

    let scale = 1;
    // If we know the original image size, attempt to upscale the image.
    // - For SVG images, use 2x or greater for the scale since they can
    //   be expanded without losing quality.
    // - For regular non-SVG images, use 1 (original size). Use the
    //   saved scale if it's greater than 1, so that the exploration
    //   modal won't have a smaller image than the original.
    if (backgroundImage.width && backgroundImage.height) {
        scale = imageIsSvg
            ? Math.max(contentScale, 2)
            : Math.max(contentScale, 1);
    }

    // Note: backgroundImage.height and backgroundImage.width may be undefined.
    let height: number | undefined = backgroundImage.height;
    let width: number | undefined = backgroundImage.width;

    // If we know what the original image size is, use it to compute the
    // image size for the modal with the scale applied.
    if (backgroundImage.height && backgroundImage.width) {
        // Pass in the original width and height into SVGImage so that
        // it calculates graphie label sizes correctly.
        width = backgroundImage.width;
        height = backgroundImage.height;

        // The part that we need to calculate is the scale that we want
        // to pass into SVGImage alongside the original dimensions in order
        // to get our image to the size it should be within the modal.
        // We don't want the scale to cause the image to be larger
        // than the modal height, so we cap it here.
        const maxScale = MODAL_HEIGHT / backgroundImage.height;
        scale = Math.min(scale, maxScale);
    }

    return (
        <div className={styles.modalPanelContainer}>
            <div className={styles.modalImageContainer}>
                {/* Need to use SvgImage in order to load Graphie images */}
                <AssetContext.Consumer>
                    {({setAssetStatus}) => (
                        <SvgImage
                            src={backgroundImage.url!}
                            // Don't allow opening a modal within a modal.
                            allowZoom={false}
                            alt={caption === alt ? "" : alt}
                            width={width}
                            height={height}
                            scale={scale}
                            preloader={apiOptions.imagePreloader}
                            extraGraphie={{
                                box: box,
                                range: range,
                                labels: labels ?? [],
                            }}
                            zoomToFullSizeOnMobile={apiOptions.isMobile}
                            constrainHeight={apiOptions.isMobile}
                            allowFullBleed={apiOptions.isMobile}
                            setAssetStatus={setAssetStatus}
                            isGifPlaying={
                                gifControlsFF && imageIsGif
                                    ? isGifPlaying
                                    : undefined
                            }
                            onGifLoop={
                                gifControlsFF && imageIsGif
                                    ? () => setIsGifPlaying(false)
                                    : undefined
                            }
                        />
                    )}
                </AssetContext.Consumer>
            </div>
            <div
                className={`perseus-image-modal-description ${styles.modalDescriptionContainer}`}
            >
                {gifControlsFF && imageIsGif && (
                    <>
                        <GifControlsButton
                            isPlaying={isGifPlaying}
                            onToggle={() => setIsGifPlaying(!isGifPlaying)}
                        />
                        <div className={styles.spacerVertical} />
                    </>
                )}

                {caption && (
                    <div
                        id={captionId}
                        className={styles.modalCaptionContainer}
                    >
                        {/* Use Renderer so that the caption can support markdown and TeX. */}
                        <Renderer
                            content={caption}
                            apiOptions={apiOptions}
                            linterContext={linterContext}
                            strings={context.strings}
                        />
                    </div>
                )}

                <Heading
                    size="large"
                    tag="h2"
                    style={wbStyles.descriptionHeading}
                >
                    {context.strings.imageDescriptionLabel}
                </Heading>
                {/* Use Renderer so that the description can support markdown and TeX. */}
                <div id={longDescId}>
                    <Renderer
                        content={longDescription}
                        apiOptions={apiOptions}
                        linterContext={linterContext}
                        strings={context.strings}
                    />
                </div>
            </div>
        </div>
    );
}

// TODO(LEMS-3686): Use CSS modules after Wonder Blocks styles
// are moved to a different layer.
const wbStyles = {
    descriptionHeading: {
        marginBlockEnd: sizing.size_160,
    },
};

