    const {
        onFocusChange: _,
        answerableCallback: __,
        getAnotherHint: ___,
        interactionCallback: ____,
        imagePreloader: _____,
        trackInteraction: ______,
        baseElements: _______,
        nativeKeypadProxy: ________,
